                return False
            # a is suffix of b
            return b[-len(a):] == a

        n = len(words)
        ans = 0
        for i in range(n):
            for j in range(i + 1, n):
                if is_prefix_and_suffix(words[i], words[j]):
                    ans += 1
        return ans
